import json

def calculateStatistics(scores_json):
    try:
        data = json.loads(scores_json)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON format")

    if not isinstance(data, list):
        raise TypeError("Input data is not a list")

    scores = []
    for item in data:
        try:
            scores.append(float(item))
        except (TypeError, ValueError):
            continue

    if not scores:
        raise ValueError("No valid numeric scores found")

    sorted_scores = sorted(scores)
    n = len(sorted_scores)
    mean = sum(sorted_scores) / n

    median = sorted_scores[n // 2] if n % 2 else (sorted_scores[n // 2 - 1] + sorted_scores[n // 2]) / 2

    frequency = {}
    for num in sorted_scores:
        frequency[num] = frequency.get(num, 0) + 1
    max_freq = max(frequency.values())
    for num in sorted_scores:
        if frequency[num] == max_freq:
            mode = num
            break

    return {'mean': mean, 'median': median, 'mode': mode}
