import java.util.*;

public class TrafficOptimizer {
    public static class Edge {
        String target;
        int traffic;

        public Edge(String t, int traffic) {
            target = t;
            this.traffic = traffic;
        }
    }

    public static Map<String, Map<String, List<String>>> trafficOptimizer(Map<String, List<Edge>> graph) {
        Map<String, Map<String, List<String>>> paths = new HashMap<>();
        for (String node : graph.keySet()) {
            paths.put(node, new HashMap<>());
            PriorityQueue<QueueNode> pq = new PriorityQueue<>();
            Map<String, Integer> dist = new HashMap<>();
            Map<String, String> prev = new HashMap<>();
            for (String v : graph.keySet()) {
                dist.put(v, Integer.MAX_VALUE);
            }
            dist.put(node, 0);
            pq.add(new QueueNode(node, 0));
            while (!pq.isEmpty()) {
                QueueNode current = pq.poll();
                if (current.distance > dist.get(current.node)) continue;
                for (Edge edge : graph.get(current.node)) {
                    int alt = current.distance + edge.traffic;
                    if (alt < dist.get(edge.target)) {
                        dist.put(edge.target, alt);
                        prev.put(edge.target, current.node);
                        pq.add(new QueueNode(edge.target, alt));
                    }
                }
            }
            for (String dest : graph.keySet()) {
                if (dest.equals(node)) continue;
                LinkedList<String> path = new LinkedList<>();
                String current = dest;
                while (current != null && !current.equals(node)) {
                    path.addFirst(current);
                    current = prev.get(current);
                }
                if (current == null) continue;
                path.addFirst(node);
                paths.get(node).put(dest, path);
            }
        }
        return paths;
    }

    static class QueueNode implements Comparable<QueueNode> {
        String node;
        int distance;

        public QueueNode(String n, int d) {
            node = n;
            distance = d;
        }

        @Override
        public int compareTo(QueueNode other) {
            return Integer.compare(distance, other.distance);
        }
    }
}
