    if numbers.is_empty() {
        return None;
    }

    let mut min = numbers[0];
    let mut max = numbers[0];
    let mut sum: i64 = 0;

    for &num in numbers {
        if num < min {
            min = num;
        }
        if num > max {
            max = num;
        }
        sum += num as i64;
    }

    let average = sum as f64 / numbers.len() as f64;

