import java.util.*;

public class NetworkAnalyzer {
    public static List<Integer> analyzeNetworkConnectivity(List<List<Integer>> graph) {
        int n = graph.size();
        boolean[] visited = new boolean[n];
        int[] disc = new int[n];
        int[] low = new int[n];
        int[] parent = new int[n];
        Arrays.fill(parent, -1);
        Set<Integer> result = new HashSet<>();
        int[] time = {0};

        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                dfs(i, visited, disc, low, parent, result, graph, time);
            }
        }

        return new ArrayList<>(result);
    }

    private static void dfs(int u, boolean[] visited, int[] disc, int[] low, int[] parent, Set<Integer> result, List<List<Integer>> graph, int[] time) {
        int children = 0;
        visited[u] = true;
        disc[u] = low[u] = time[0]++;
        for (int v : graph.get(u)) {
            if (!visited[v]) {
                children++;
                parent[v] = u;
                dfs(v, visited, disc, low, parent, result, graph, time);
                low[u] = Math.min(low[u], low[v]);
                if (parent[u] == -1 && children > 1) {
                    result.add(u);
                }
                if (parent[u] != -1 && low[v] >= disc[u]) {
                    result.add(u);
                }
            } else if (v != parent[u]) {
                low[u] = Math.min(low[u], disc[v]);
            }
        }
    }
}
