pub fn manage_airport_gates(action: GateAction) -> Result<GateStatus, String> {
    let mut state = STATE.lock().map_err(|e| e.to_string())?;
    let gate_id = action.gate_details.identifier;

    match action.action_type {
        ActionType::Allocate => {
            if state.allocated.insert(gate_id) {
                Ok(GateStatus::Allocated)
            } else {
                Err("Gate already allocated".into())
            }
        }
        ActionType::Deallocate => {
            if state.allocated.remove(&gate_id) {
                Ok(GateStatus::Deallocated)
            } else {
                Err("Gate not found".into())
            }
        }
        ActionType::StatusCheck => {
            let status = state.allocated.contains(&gate_id);
            Ok(GateStatus::Available(status))
        }
    }
