public class LoginHistoryManager {
    private static Map<String, List<String>> loginHistory = new ConcurrentHashMap<>();

    public static String processLoginHistory(String jsonInput) {
        try {
            JSONObject input = new JSONObject(jsonInput);
            String operation = input.getString("operation");
            JSONObject data = input.getJSONObject("data");

            switch (operation) {
                case "add":
                    String userId = data.getString("user_id");
                    String timestamp = data.getString("timestamp");
                    List<String> userLogins = loginHistory.computeIfAbsent(userId, k -> Collections.synchronizedList(new ArrayList<>()));
                    userLogins.add(timestamp);
                    return new JSONObject().put("status", "success").toString();

                case "retrieve":
                    String retrieveUserId = data.getString("user_id");
                    int limit = data.optInt("limit", 10);
                    List<String> logins = loginHistory.getOrDefault(retrieveUserId, Collections.emptyList());
                    int fromIndex = Math.max(0, logins.size() - limit);
                    JSONArray loginsArray = new JSONArray(logins.subList(fromIndex, logins.size()));
                    return new JSONObject().put("status", "success").put("data", loginsArray).toString();

                case "delete":
                    String deleteUserId = data.getString("user_id");
                    loginHistory.remove(deleteUserId);
                    return new JSONObject().put("status", "success").toString();

                default:
                    return new JSONObject().put("status", "error").put("message", "Invalid operation").toString();
            }
        } catch (JSONException e) {
            return new JSONObject().put("status", "error").put("message", "Invalid JSON input or missing required fields").toString();
        }
    }
