#include <vector>
#include <string>
#include <sstream>

using namespace std;

struct PermissionNode {
    string name;
    vector<PermissionNode*> children;
};

struct OperationNode {
    enum class Type { ADD, UPDATE, REMOVE };
    Type type;
    string targetPath;
    string newName;
    vector<OperationNode*> children;
};

vector<string> splitPath(const string& path) {
    vector<string> components;
    stringstream ss(path);
    string component;
    while (getline(ss, component, '/')) {
        if (!component.empty()) components.push_back(component);
    }
    return components;
}

PermissionNode* findNodeByPath(PermissionNode* root, const string& path) {
    vector<string> components = splitPath(path);
    PermissionNode* current = root;
    for (const auto& comp : components) {
        bool found = false;
        for (auto child : current->children) {
            if (child->name == comp) {
                current = child;
                found = true;
                break;
            }
        }
        if (!found) return nullptr;
    }
    return current;
}

void processOperation(PermissionNode* permissionTree, OperationNode* op) {
    if (op->type == OperationNode::Type::REMOVE) {
        vector<string> pathComponents = splitPath(op->targetPath);
        if (pathComponents.empty()) return;
        string nodeNameToRemove = pathComponents.back();
        pathComponents.pop_back();
        string parentPath;
        for (const auto& comp : pathComponents) parentPath += "/" + comp;
        if (parentPath.empty()) parentPath = "/";
        PermissionNode* parentNode = findNodeByPath(permissionTree, parentPath);
        if (!parentNode) return;
        for (auto it = parentNode->children.begin(); it != parentNode->children.end(); ++it) {
            if ((*it)->name == nodeNameToRemove) {
                delete *it;
                parentNode->children.erase(it);
                break;
            }
        }
    } else {
        PermissionNode* targetNode = findNodeByPath(permissionTree, op->targetPath);
        if (!targetNode) return;
        if (op->type == OperationNode::Type::ADD) {
            PermissionNode* newNode = new PermissionNode;
            newNode->name = op->newName;
            targetNode->children.push_back(newNode);
        } else if (op->type == OperationNode::Type::UPDATE) {
            targetNode->name = op->newName;
        }
    }
}

void managePermissions(PermissionNode* permissionTree, OperationNode* operations) {
    if (!operations) return;
    processOperation(permissionTree, operations);
    for (auto childOp : operations->children) managePermissions(permissionTree, childOp);
}
