pub fn process_grid_operations(mut matrix: Vec<Vec<i32>>, operations: &[String]) -> Vec<Vec<i32>> {
    for op in operations {
        match op.as_str() {
            "rotate" => matrix = rotate(matrix),
            "flip" => flip(&mut matrix),
            "invert" => invert(&mut matrix),
            _ => (),
        }
