fn rotate(mut matrix: Vec<Vec<i32>>) -> Vec<Vec<i32>> {
    matrix.reverse();
    if matrix.is_empty() {
        return matrix;
    }
    let cols = matrix[0].len();
    let mut transposed = Vec::with_capacity(cols);
    for i in 0..cols {
        let mut new_row = Vec::new();
        for row in &matrix {
            new_row.push(row[i]);
        }
        transposed.push(new_row);
    }
    transposed
}

fn flip(matrix: &mut Vec<Vec<i32>>) {
    for row in matrix {
        row.reverse();
    }
}

fn invert(matrix: &mut Vec<Vec<i32>>) {
    for row in matrix {
        for num in row {
            if *num == 0 {
                *num = 1;
            } else if *num == 1 {
                *num = 0;
            }
        }
    }
}
