public class PaymentProcessor {
    public static String processPaymentInfo(String jsonInput) {
        try {
            JSONObject paymentDetails = new JSONObject(jsonInput);
            String cardNumber = paymentDetails.getString("cardNumber").replaceAll("[^0-9]", "");
            boolean isValid = isValidLuhn(cardNumber);
            JSONObject result = new JSONObject();
            result.put("isValid", isValid);
            result.put("transactionStatus", isValid ? "Approved" : "Declined");
            return result.toString();
