use std::collections::HashMap;
use std::rc::Rc;
use std::cell::RefCell;

pub enum ActionType {
    Add,
    Update,
    Remove,
    Retrieve,
}

pub struct NetworkNode {
    name: String,
    config: HashMap<String, String>,
    children: HashMap<String, Rc<RefCell<NetworkNode>>>,
}

impl NetworkNode {
    fn add_child(&mut self, name: String, config: HashMap<String, String>) {
        self.children.insert(name.clone(), Rc::new(RefCell::new(NetworkNode {
            name,
            config,
            children: HashMap::new(),
        })));
    }

    fn update_config(&mut self, config: HashMap<String, String>) {
        self.config = config;
    }

    fn remove_child(&mut self, name: &str) {
        self.children.remove(name);
    }

    fn get_config(&self) -> &HashMap<String, String> {
        &self.config
    }
}

fn find_node(node: Rc<RefCell<NetworkNode>>, path: &[String]) -> Option<Rc<RefCell<NetworkNode>>> {
    let mut current = node;
    for part in path {
        let next = current.borrow().children.get(part)?.clone();
        current = next;
    }
    Some(current)
}

fn find_parent(node: Rc<RefCell<NetworkNode>>, path: &[String]) -> Option<(Rc<RefCell<NetworkNode>>, String)> {
    if path.is_empty() {
        return None;
    }
    let parent_path = &path[..path.len()-1];
    let child_name = &path[path.len()-1];
    let parent = find_node(node, parent_path)?;
    Some((parent, child_name.clone()))
}

pub fn manageNetworkConfig(
    action: ActionType,
    root: Rc<RefCell<NetworkNode>>,
    path: Vec<String>,
    config: Option<HashMap<String, String>>,
) -> Option<HashMap<String, String>> {
    match action {
        ActionType::Add => {
            let (parent, child_name) = find_parent(root.clone(), &path)?;
            let config = config?;
            parent.borrow_mut().add_child(child_name, config);
            None
        }
        ActionType::Update => {
            let node = find_node(root.clone(), &path)?;
            let config = config?;
            node.borrow_mut().update_config(config);
            None
        }
        ActionType::Remove => {
            let (parent, child_name) = find_parent(root.clone(), &path)?;
            parent.borrow_mut().remove_child(&child_name);
            None
        }
        ActionType::Retrieve => {
            let node = find_node(root.clone(), &path)?;
            Some(node.borrow().get_config().clone())
        }
    }
}
