import org.json.JSONObject;
import java.util.*;

public class FileSystemSimulator {
    private static class Folder {
        String name;
        Folder parent;
        List<Folder> children = new ArrayList<>();

        Folder(String name) {
            this.name = name;
        }
    }

    private static Folder root = new Folder("");
    private static Map<String, Folder> folders = new HashMap<>();

    public static String fs_simulator(String inputJson) {
        JSONObject input = new JSONObject(inputJson);
        String action = input.getString("action");
        switch (action) {
            case "add":
                return addFolder(input.getString("name"), input.getString("parentPath"));
            case "move":
                return moveFolder(input.getString("name"), input.getString("newParentPath"));
            case "remove":
                return removeFolder(input.getString("name"));
            case "fetch":
                return getPath(input.getString("name"));
            default:
                return "Invalid action";
        }
    }

    private static String addFolder(String name, String parentPath) {
        if (folders.containsKey(name)) return "Error: Folder already exists";
        Folder parent = findFolderByPath(parentPath);
        if (parent == null) return "Error: Parent path not found";
        Folder newFolder = new Folder(name);
        newFolder.parent = parent;
        parent.children.add(newFolder);
        folders.put(name, newFolder);
        return "Success";
    }

    private static Folder findFolderByPath(String path) {
        if (path.equals("/") || path.isEmpty()) return root;
        String[] parts = path.replaceAll("^/|/$", "").split("/");
        Folder current = root;
        for (String part : parts) {
            boolean found = false;
            for (Folder child : current.children) {
                if (child.name.equals(part)) {
                    current = child;
                    found = true;
                    break;
                }
            }
            if (!found) return null;
        }
        return current;
    }

    private static String moveFolder(String name, String newParentPath) {
        Folder folder = folders.get(name);
        if (folder == null) return "Error: Folder not found";
        Folder newParent = findFolderByPath(newParentPath);
        if (newParent == null) return "Error: New parent path not found";
        if (isDescendant(newParent, folder)) return "Error: Cannot move folder to its descendant";
        folder.parent.children.remove(folder);
        newParent.children.add(folder);
        folder.parent = newParent;
        return "Success";
    }

    private static boolean isDescendant(Folder parent, Folder child) {
        Folder current = child;
        while (current != null) {
            if (current == parent) return true;
            current = current.parent;
        }
        return false;
    }

    private static String removeFolder(String name) {
        Folder folder = folders.get(name);
        if (folder == null) return "Error: Folder not found";
        List<Folder> toRemove = new ArrayList<>();
        collectDescendants(folder, toRemove);
        for (Folder f : toRemove) folders.remove(f.name);
        folder.parent.children.remove(folder);
        return "Success";
    }

    private static void collectDescendants(Folder folder, List<Folder> list) {
        list.add(folder);
        for (Folder child : folder.children) collectDescendants(child, list);
    }

    private static String getPath(String name) {
        Folder folder = folders.get(name);
        if (folder == null) return "Error: Folder not found";
        List<String> pathParts = new ArrayList<>();
        Folder current = folder;
        while (current != root) {
            pathParts.add(current.name);
            current = current.parent;
        }
        Collections.reverse(pathParts);
        return "/" + String.join("/", pathParts);
    }
}
