fn calculate_divisors(n: i32) -> Vec<i32> {
    if n <= 0 {
        return Vec::new();
    }
    if n == 1 {
        return vec![1];
    }
    let mut lower = vec![1];
    let mut upper = vec![n];
    let sqrt_n = (n as f64).sqrt() as i32;
    for i in 2..=sqrt_n {
        if n % i == 0 {
            lower.push(i);
            let counterpart = n / i;
            if counterpart != i {
                upper.push(counterpart);
            }
        }
    }
    upper.reverse();
    lower.append(&mut upper);
    lower
}
