public static int[][] transformMatrix(int[][] matrix, String operation) {
    if (matrix.length == 0) {
        return new int[0][0];
    }
    int m = matrix.length;
    int n = matrix[0].length;
    switch (operation) {
        case "rotate_left":
            int[][] reversedRows = new int[m][n];
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    reversedRows[i][j] = matrix[i][n - 1 - j];
                }
            }
            int[][] rotatedLeft = new int[n][m];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    rotatedLeft[i][j] = reversedRows[j][i];
                }
            }
            return rotatedLeft;
        case "rotate_right":
            int[][] transposed = new int[n][m];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    transposed[i][j] = matrix[j][i];
                }
            }
            int[][] rotatedRight = new int[n][m];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    rotatedRight[i][j] = transposed[i][m - 1 - j];
                }
            }
            return rotatedRight;
        case "flip_vertical":
            int[][] flippedVertical = new int[m][n];
            for (int i = 0; i < m; i++) {
                flippedVertical[i] = matrix[m - 1 - i].clone();
            }
            return flippedVertical;
        case "flip_horizontal":
            int[][] flippedHorizontal = new int[m][n];
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
